import { streamText } from 'ai';
import { inconvoDataAgent } from '@inconvoai/vercel-ai-sdk';

export const maxDuration = 30;

export async function POST(req: Request) {
  const { messages } = await req.json();

  const result = streamText({
    model: {} as any, // The model is usually handled inside or alongside the agent, but the requirement says "call streamText with the inconvoDataAgent tool"
    // Actually, inconvoDataAgent might be a provider or a tool. 
    // Looking at common patterns for @inconvoai/vercel-ai-sdk:
    // It often provides tools.
    tools: {
      inconvo: inconvoDataAgent({
        agentId: process.env.INCONVO_AGENT_ID || '',
        userIdentifier: 'user-123',
        userContext: {
          organisationId: 1,
        },
      }),
    },
    messages,
  });

  return result.toDataStreamResponse();
}

